// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { Paper, Typography, Grid, Card, CardContent, Table, TableHead, TableBody, TableRow, TableCell, Button, CircularProgress } from "@mui/material";
import { People, DirectionsBike, HowToReg, HourglassBottom, Logout } from "@mui/icons-material";
import { getOverview, getUsers, getRiders, getApprovedCaptains, getPendingCaptains, approveCaptain, rejectCaptain } from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [tab, setTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  const { logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate("/admin");
  };

  // Fetch overview counts
  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data);
    } catch (err) {
      console.error("Overview error:", err);
    }
  };

  // Fetch table data based on selected tab
  const fetchTabData = async () => {
    setLoading(true);
    try {
      let res;
      if (tab === "users") res = await getUsers();
      else if (tab === "riders") res = await getRiders();
      else if (tab === "approved") res = await getApprovedCaptains();
      else if (tab === "pending") res = await getPendingCaptains();
      setData(res?.data?.users || res?.data?.riders || res?.data?.captains || res?.data?.pendingCaptains || []);
    } catch (err) {
      console.error("Fetch tab data error:", err);
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOverview();
    fetchTabData();
  }, [tab]);

  const handleApprove = async (id) => {
    await approveCaptain(id);
    fetchOverview();
    fetchTabData();
  };

  const handleReject = async (id) => {
    await rejectCaptain(id);
    fetchOverview();
    fetchTabData();
  };

  const cards = [
    { title: "Users", value: overview.users || 0, icon: <People />, tab: "users" },
    { title: "Riders", value: overview.riders || 0, icon: <DirectionsBike />, tab: "riders" },
    { title: "Approved Captains", value: overview.captains || 0, icon: <HowToReg />, tab: "approved" },
    { title: "Pending Captains", value: overview.pendingCaptains || 0, icon: <HourglassBottom />, tab: "pending" },
    { title: "Total Rides", value: overview.rides || 0, icon: <DirectionsBike />, tab: "rides" },
  ];

  return (
    <div>
      <Grid container justifyContent="space-between" alignItems="center" sx={{ mb: 3 }}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="contained" color="secondary" startIcon={<Logout />} onClick={handleLogout}>
          Logout
        </Button>
      </Grid>

      {/* Overview cards */}
      <Grid container spacing={2} sx={{ mb: 4 }}>
        {cards.map((card) => (
          <Grid item xs={12} sm={6} md={2.4} key={card.title}>
            <Card sx={{ cursor: "pointer" }} onClick={() => setTab(card.tab)}>
              <CardContent sx={{ display: "flex", alignItems: "center", gap: 1 }}>
                {card.icon}
                <div>
                  <Typography variant="h6">{card.title}</Typography>
                  <Typography variant="h5">{card.value}</Typography>
                </div>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {/* Table for selected tab */}
      <Paper sx={{ p: 2 }}>
        <Typography variant="h6" gutterBottom>
          {tab === "users"
            ? "Users"
            : tab === "riders"
            ? "Riders"
            : tab === "approved"
            ? "Approved Captains"
            : tab === "pending"
            ? "Pending Captains"
            : "Data"}
        </Typography>

        {loading ? (
          <CircularProgress />
        ) : data.length === 0 ? (
          <Typography>No data found.</Typography>
        ) : (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Mobile</TableCell>
                <TableCell>Role</TableCell>
                <TableCell>Login Count</TableCell>
                <TableCell>Approval Status</TableCell>
                {tab === "pending" && <TableCell>Actions</TableCell>}
              </TableRow>
            </TableHead>
            <TableBody>
              {data.map((user) => (
                <TableRow key={user._id}>
                  <TableCell>{user.fullName}</TableCell>
                  <TableCell>{user.email}</TableCell>
                  <TableCell>{user.mobile}</TableCell>
                  <TableCell>{user.role}</TableCell>
                  <TableCell>{user.loginCount || 0}</TableCell>
                  <TableCell>{user.approvalStatus}</TableCell>
                  {tab === "pending" && (
                    <TableCell>
                      <Button color="success" onClick={() => handleApprove(user._id)}>
                        Approve
                      </Button>
                      <Button color="error" onClick={() => handleReject(user._id)}>
                        Reject
                      </Button>
                    </TableCell>
                  )}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </Paper>
    </div>
  );
}
